    public GroupCat delete(GroupCatId groupcatId) {
        LOGGER.debug("Deleting GroupCat with id: {}", groupcatId);
        GroupCat deleted = this.wmGenericDao.findById(groupcatId);
        if (deleted == null) {
            LOGGER.debug("No GroupCat found with id: {}", groupcatId);
            throw new EntityNotFoundException(MessageResource.create("com.wavemaker.runtime.entity.not.found"), GroupCat.class.getSimpleName(), groupcatId);
        }
        this.wmGenericDao.delete(deleted);
        return deleted;
    }

